const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };
const warn  = (...args) => { if (DEBUG) console.log('[WARN]', ...args); };

// ── Helpers ─────────────────────────────────────────────────────────────
function buildFallback(projects) {
  warn('Falling back to full Airtable project list.');
  return projects.map(p => ({
    json: {
      workstream: p.fields.Name,
      jiraKey:    p.fields.JiraKey,
      priority:   'medium',
      _fallback:  true
    }
  }));
}

// ── 1. Extract raw LLM output ────────────────────────────────────────────
const response = $input.first().json;
const projects = $('Build Orchestrator prompt').first().json.projects;

if (!response.choices || response.choices.length === 0) {
  warn('Orchestrator returned no choices. Using fallback.');
  return buildFallback(projects);
}

const raw   = response.choices[0].message.content ?? '';
const clean = raw.replace(/```json|```/gi, '').trim();

// ── 2. Attempt parse ─────────────────────────────────────────────────────
let plan;
try {
  plan = JSON.parse(clean);
} catch (e) {
  warn('Orchestrator returned invalid JSON: ' + raw.slice(0, 300));
  return buildFallback(projects);
}

// ── 3. Validate it's a non-empty array ───────────────────────────────────
if (!Array.isArray(plan) || plan.length === 0) {
  warn('Orchestrator returned empty or non-array plan. Using fallback.');
  return buildFallback(projects);
}

// ── 4. Validate each item has the minimum required fields ────────────────
const validItems   = [];
const invalidItems = [];

plan.forEach((p, i) => {
  const missingFields = ['workstream', 'jiraKey'].filter(
    f => !p[f] || p[f].toString().trim() === ''
  );
  if (missingFields.length > 0) {
    warn(`Plan item[${i}] missing fields: ${missingFields.join(', ')}. Dropping item.`);
    invalidItems.push(p);
  } else {
    validItems.push(p);
  }
});

// ── 5. If too many items are invalid, fall back entirely ─────────────────
const invalidRatio = invalidItems.length / plan.length;
if (validItems.length === 0 || invalidRatio > 0.5) {
  warn(
    `Too many invalid plan items (${invalidItems.length}/${plan.length}). Using fallback.`
  );
  return buildFallback(projects);
}

// ── 6. Return valid items, flagging any partial fallback ─────────────────
log(`Orchestrator plan accepted: ${validItems.length} valid items, ${invalidItems.length} dropped.`);
return validItems.map(p => ({
  json: {
    workstream: p.workstream.trim(),
    jiraKey:    p.jiraKey.trim(),
    priority:   p.priority ?? 'medium',
    _fallback:  false
  }
}));

const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };

const statusRecords = $input.all().map(i => ({
  ...i.json,
  weekStart: $now.startOf('week').toISO()
}));

log('Status records wrapped:', statusRecords.length);
log('Workstreams:', statusRecords.map(r => r.workstream).join(', '));

return [{
  json: {
    statusRecords
  }
}];

// Runs once for all items — no Python required
const projects = $input.all().map(i => i.json);

const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };
const warn  = (...args) => { if (DEBUG) console.log('[WARN]', ...args); };

const validProjects = projects.filter(p => {
  const hasName    = p.fields?.Name    && p.fields.Name.trim()    !== '';
  const hasJiraKey = p.fields?.JiraKey && p.fields.JiraKey.trim() !== '';
  if (!hasName || !hasJiraKey) {
    warn('Skipping Airtable record missing Name or JiraKey:', JSON.stringify(p.fields));
  }
  return hasName && hasJiraKey;
});

if (validProjects.length === 0) {
  throw new Error(
    'All Airtable project records are missing Name or JiraKey fields. ' +
    'Check that both columns are populated in the Projects table.'
  );
}

log('Valid projects for orchestrator:', validProjects.length);

const projectList = validProjects
  .map(p => `- ${p.fields.Name} (key: ${p.fields.JiraKey})`)
  .join('\n');

const systemPrompt = `You are a program orchestrator agent.
Active projects:
${projectList}
Today: ${new Date().toDateString()}
Goal: Produce the weekly exec brief.
Return ONLY a valid JSON array, no markdown fences:
[{"workstream":"name","jiraKey":"KEY","priority":"high|medium|low"}]`;

return [{ json: { systemPrompt, validProjects } }];

// Code node before Slack — final version
// Language: JavaScript

const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };
const warn  = (...args) => { if (DEBUG) console.log('[WARN]', ...args); };

const input = $input.first().json;

// Get brief content
const briefMarkdown = input.briefMarkdown ?? '';
const overallRag    = (input.overallRag ?? 'amber').toUpperCase();
const generatedAt   = input.generatedAt ?? new Date().toISOString();

// Build docUrl from id field — id is present in input
const fileId = input.id
  ?? input.fileId
  ?? null;

const docUrl = input.docUrl && input.docUrl.length > 0
  ? input.docUrl
  : fileId
    ? `https://drive.google.com/file/d/${fileId}/view?usp=sharing`
    : 'https://drive.google.com';

log('fileId:', fileId);
log('docUrl:', docUrl);

// Strip image markdown — Slack does not render images
const cleanBrief = briefMarkdown
  .replace(/!\[.*?\]\(.*?\)/g, '')
  .replace(/\n{3,}/g, '\n\n')
  .trim()
  .slice(0, 2900);

// Build Slack blocks
const slackBlocks = [
  {
    type: "header",
    text: { type: "plain_text", text: "Weekly exec brief ready for review" }
  },
  {
    type: "section",
    fields: [
      { type: "mrkdwn", text: "*Overall status*\n" + overallRag },
      { type: "mrkdwn", text: "*Generated*\n" + new Date().toDateString() }
    ]
  },
  {
    type: "section",
    text: { type: "mrkdwn", text: cleanBrief }
  },
  {
    type: "section",
    text: {
      type: "mrkdwn",
      text: "<" + docUrl + "|Open full brief in Google Drive>"
    }
  },
  { type: "divider" },
  {
    type: "actions",
    elements: [
      {
        type: "button",
        text: { type: "plain_text", text: "Approve and send" },
        style: "primary",
        action_id: "approve_brief",
        value: docUrl
      },
      {
        type: "button",
        text: { type: "plain_text", text: "Request edit" },
        style: "danger",
        action_id: "request_edit",
        value: "request_edit"
      }
    ]
  }
];

return [{
  json: {
    briefMarkdown,
    overallRag: input.overallRag ?? 'amber',
    docUrl,
    fileId,
    generatedAt,
    slackBlocks
  }
}];

